## Why This Is Asked
Tests the ability to design a cross-platform native module and a consumer-friendly React hook, focusing on bridging, event emission, platform-specific APIs, and power awareness.

## Key Concepts
- React Native bridging (NativeModules, NativeEventEmitter)
- iOS: UIDevice battery APIs, RCTDeviceEventEmitter
- Android: BroadcastReceiver, Intent filters for ACTION_BATTERY_CHANGED
- Hook patterns for subscribing to native events
- Power consumption considerations

## Code Example

```javascript
// useBattery.ts - React hook
import { useState, useEffect } from 'react';
import { NativeModules, NativeEventEmitter, Platform } from 'react-native';

const { BatteryModule } = NativeModules;
const batteryEmitter = new NativeEventEmitter(BatteryModule);

interface BatteryState {
  level: number;      // 0-100 (normalized)
  charging: boolean;
}

export function useBattery(): BatteryState {
  const [battery, setBattery] = useState<BatteryState>({
    level: 100,
    charging: false,
  });

  useEffect(() => {
    // Get initial values
    BatteryModule.getBatteryLevel().then((level: number) => {
      setBattery(prev => ({ ...prev, level }));
    });
    BatteryModule.isCharging().then((charging: boolean) => {
      setBattery(prev => ({ ...prev, charging }));
    });

    // Subscribe to updates
    const subscription = batteryEmitter.addListener(
      'onBatteryChange',
      (event: { level: number; charging: boolean }) => {
        setBattery({ level: event.level, charging: event.charging });
      }
    );

    return () => subscription.remove();
  }, []);

  return battery;
}
```

```swift
// iOS: BatteryModule.swift
import UIKit
import React

@objc(BatteryModule)
class BatteryModule: RCTEventEmitter {
  override init() {
    super.init()
    UIDevice.current.isBatteryMonitoringEnabled = true
  }

  @objc func getBatteryLevel(_ resolve: @escaping RCTPromiseResolveBlock,
                            rejecter reject: @escaping RCTPromiseRejectBlock) {
    resolve(UIDevice.current.batteryLevel)
  }

  @objc func isCharging(_ resolve: @escaping RCTPromiseResolveBlock,
                        rejecter reject: @escaping RCTPromiseRejectBlock) {
    let state = UIDevice.current.batteryState
    resolve(state == .charging || state == .full)
  }

  @objc override func supportedEvents() -> [String]! {
    return ["onBatteryChange"]
  }
}
```

```kotlin
// Android: BatteryModule.kt
package com.example.battery

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import com.facebook.react.bridge.*
import com.facebook.react.modules.core.DeviceEventManagerModule

class BatteryModule(reactContext: ReactApplicationContext) : ReactContextBaseJavaModule(reactContext) {
    private var receiver: BroadcastReceiver? = null

    override fun getName() = "BatteryModule"

    @ReactMethod
    fun getBatteryLevel(promise: Promise) {
        val intent = reactApplicationContext.registerReceiver(null, IntentFilter(Intent.ACTION_BATTERY_CHANGED))
        val level = intent?.getIntExtra(Intent.EXTRA_LEVEL, -1) ?: -1
        val scale = intent?.getIntExtra(Intent.EXTRA_SCALE, 100) ?: 100
        promise.resolve((level * 100) / scale)
    }

    @ReactMethod
    fun isCharging(promise: Promise) {
        val intent = reactApplicationContext.registerReceiver(null, IntentFilter(Intent.ACTION_BATTERY_CHANGED))
        val status = intent?.getIntExtra(android.os.BatteryManager.EXTRA_STATUS, -1) ?: -1
        promise.resolve(status == android.os.BatteryManager.BATTERY_STATUS_CHARGING ||
                        status == android.os.BatteryManager.BATTERY_STATUS_FULL)
    }

    @ReactMethod
    fun addListener(eventName: String) {}

    @ReactMethod
    fun removeListeners(count: Int) {}
}
```

